module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

reg [1:0] cnt;
reg valid;
reg [3:0] data;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 2'b00;
        valid <= 1'b0;
        data <= 4'b0000;
    end else begin
        if (cnt == 2'b11) begin
            data <= d;
            cnt <= 2'b00;
            valid <= 1'b1;
        end else begin
            data <= {data[2:0], data[3]};
            cnt <= cnt + 2'b01;
            valid <= 1'b0;
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule
